Create a file named 'estimate-fees.ts' in papi-fee-estimate with this content:

```typescript
import { createClient } from "polkadot-api";
import { getWsProvider } from "polkadot-api/ws-provider/node";
import { polkadotTestNet } from "@polkadot-api/descriptors";

const WS_ENDPOINT = "INSERT_WS_ENDPOINT";
const SENDER_ADDRESS = "INSERT_SENDER_ADDRESS";
const DEST_ADDRESS = "INSERT_DEST_ADDRESS";

async function main() {
  const client = createClient(getWsProvider(WS_ENDPOINT));
  const api = client.getTypedApi(polkadotTestNet);
  const tx = api.tx.Balances.transfer_keep_alive({
    dest: { type: "Id", value: DEST_ADDRESS },
    value: 10_000_000_000n,
  });
  const info = await tx.getPaymentInfo(SENDER_ADDRESS);
  console.log("Fee (planck):", info.partial_fee.toString());
  console.log("Fee (PAS):", (Number(info.partial_fee) / 1e10).toFixed(6));
  console.log("Weight ref_time:", info.weight.ref_time.toString());
  client.destroy();
}
main().catch(console.error);
```

After creating the file, apply these substitutions: (1) Replace INSERT_WS_ENDPOINT with your WS endpoint (e.g. 'wss://asset-hub-paseo.dotters.network'). (2) Replace INSERT_SENDER_ADDRESS with any valid funded SS58 address — sender address affects fee because weight depends on account state. (3) Replace INSERT_DEST_ADDRESS with any valid SS58 recipient address. Save the file.

Create a file named 'xcm-transfer.ts' with the following content:

```typescript
import "dotenv/config";
import { ApiPromise, WsProvider } from "@polkadot/api";
import { Keyring } from "@polkadot/keyring";
import { Builder } from "@paraspell/sdk-pjs";

const SOURCE_RPC = process.env.SOURCE_RPC!;
const MNEMONIC = process.env.MNEMONIC!;
const DEST_ADDRESS = process.env.DEST_ADDRESS!;
const SOURCE_CHAIN = "AssetHubPaseo";
const DEST_CHAIN = "PeopleChainPaseo";
const AMOUNT = "10000000000"; // 1 PAS (10 decimals)

async function main() {
  const api = await ApiPromise.create({ provider: new WsProvider(SOURCE_RPC) });
  const keyring = new Keyring({ type: "sr25519" });
  const sender = keyring.addFromMnemonic(MNEMONIC);
  console.log("Sender:", sender.address);

  const dryResult = await Builder(api)
    .from(SOURCE_CHAIN).to(DEST_CHAIN)
    .currency({ symbol: "PAS" }).amount(AMOUNT)
    .address(DEST_ADDRESS).dryRun(sender);
  console.log("Dry-run:", dryResult.success ? "OK" : "FAILED");
  if (!dryResult.success) { console.error(dryResult); process.exit(1); }

  const fee = await Builder(api)
    .from(SOURCE_CHAIN).to(DEST_CHAIN)
    .currency({ symbol: "PAS" }).amount(AMOUNT)
    .address(DEST_ADDRESS).getOriginXcmFee();
  console.log("Estimated fee:", fee.toString());

  const tx = await Builder(api)
    .from(SOURCE_CHAIN).to(DEST_CHAIN)
    .currency({ symbol: "PAS" }).amount(AMOUNT)
    .address(DEST_ADDRESS).build();
  await tx.signAndSend(sender, { nonce: -1 }, ({ status, txHash }) => {
    console.log("Status:", status.type);
    if (status.isFinalized) {
      console.log("Finalized:", status.asFinalized.toString(), "tx:", txHash.toString());
      process.exit(0);
    }
  });
}
main().catch((err) => { console.error(err); process.exit(1); });
```

Substitutions: (1) Replace SOURCE_CHAIN ('AssetHubPaseo') and DEST_CHAIN ('PeopleChainPaseo') with the actual chain names from the ParaSpell supported chains list if your transfer uses different parachains — chain names are case-sensitive. (2) PAS has 10 decimals on Paseo; '10000000000' equals 1 PAS. Verify the decimal count for the asset being transferred.

Create a file named 'fee-proxy.ts' with the following content:

```typescript
import { createClient } from "polkadot-api";
import { getWsProvider } from "polkadot-api/ws-provider/node";
import { localFork } from "@polkadot-api/descriptors";
import { getPolkadotSigner } from "polkadot-api/signer";

const ALICE = "5GrwvaEF5zXb26Fz9rcQpDWS57CtERHpNehXCPcNoHGKutQY";
const BOB = "5FHneW46xGXgs5mUiveU4sbTyGBzmstUspZC92UhjJM694ty";
const USDT_ID = 1984;

async function main() {
  const client = createClient(getWsProvider("ws://localhost:8000"));
  const api = client.getTypedApi(localFork);

  const transfer = api.tx.Balances.transfer_keep_alive({
    dest: { type: "Id", value: BOB },
    value: 1_000_000_000n,
  });

  // Wrap in asset-conversion fee proxy — pay fees in USDT
  const feeProxyTx = api.tx.AssetConversionTxPayment.asset_conversion_fee_proxy(
    USDT_ID,
    transfer
  );

  // Mock signer works because Chopsticks has mock-signature-host: true
  const mockSigner = getPolkadotSigner(
    ALICE,
    "Sr25519",
    async () => new Uint8Array(64)
  );

  const result = await feeProxyTx.signAndSubmit(mockSigner);
  console.log("Included in block:", result.block.hash);
  console.log("Fees paid in USDT asset ID:", USDT_ID);
  client.destroy();
}
main().catch(console.error);
```

Note: The exact pallet name for fee proxy varies by runtime version. If 'AssetConversionTxPayment' is not in the typed API, check the source page for the correct pallet and extrinsic name for the chain version in your fork. The mock signer returns an empty signature accepted by Chopsticks.

Create a file named 'estimate-xcm-fees.ts' with the following content:

```typescript
import { createClient } from "polkadot-api";
import { getWsProvider } from "polkadot-api/ws-provider/node";
import { hubFork } from "@polkadot-api/descriptors";
import { peopleFork } from "@polkadot-api/descriptors";

const SENDER = "INSERT_SENDER_SS58_ADDRESS";
const RECIPIENT = "INSERT_RECIPIENT_SS58_ADDRESS";
const AMOUNT = 1_000_000_000_000_000_000n; // 1 PAS (18 decimals)

async function main() {
  const hubClient = createClient(getWsProvider("ws://localhost:8000"));
  const peopleClient = createClient(getWsProvider("ws://localhost:8001"));
  const hubApi = hubClient.getTypedApi(hubFork);
  const peopleApi = peopleClient.getTypedApi(peopleFork);

  // 1. Local execution fee on Polkadot Hub (source)
  const teleportTx = hubApi.tx.PolkadotXcm.limited_teleport_assets({
    dest: { type: "V4", value: { parents: 0, interior: { type: "X1", value: { type: "Parachain", value: 1004 } } } },
    beneficiary: { type: "V4", value: { parents: 0, interior: { type: "X1", value: { type: "AccountId32", value: { network: undefined, id: RECIPIENT } } } } },
    assets: { type: "V4", value: [{ id: { parents: 1, interior: { type: "Here" } }, fun: { type: "Fungible", value: AMOUNT } }] },
    fee_asset_item: 0,
    weight_limit: { type: "Unlimited" }
  });
  const localFeeInfo = await teleportTx.getPaymentInfo(SENDER);
  console.log("Local execution fee (planck):", localFeeInfo.partial_fee.toString());

  // 2. Delivery fee
  const deliveryFee = await hubApi.apis.XcmPaymentApi.query_delivery_fees(
    { type: "V4", value: { parents: 0, interior: { type: "X1", value: { type: "Parachain", value: 1004 } } } },
    { type: "V4", value: [] }
  );
  console.log("Delivery fee assets:", JSON.stringify(deliveryFee.value));

  // 3. Remote execution fee on People Chain (destination)
  const remoteWeight = await peopleApi.apis.XcmPaymentApi.query_xcm_weight(
    { type: "V4", value: [{ type: "ReceiveTeleportedAsset", value: [] }, { type: "BuyExecution", value: { fees: { id: { parents: 1, interior: { type: "Here" } }, fun: { type: "Fungible", value: AMOUNT } }, weight_limit: { type: "Unlimited" } } }, { type: "DepositAsset", value: { assets: { type: "Wild", value: { type: "AllCounted", value: 1 } }, beneficiary: { parents: 0, interior: { type: "X1", value: { type: "AccountId32", value: { network: undefined, id: RECIPIENT } } } } } }] }
  );
  const remoteAsset = { parents: 1, interior: { type: "Here" } };
  const remoteFee = await peopleApi.apis.XcmPaymentApi.query_weight_to_asset_fee(remoteWeight.value, { type: "V4", value: { Concrete: remoteAsset } });
  console.log("Remote execution fee (planck):", remoteFee.value?.toString());
