};

export default config;
```

Key points: (1) 'dotenv/config' must be the first functional import. (2) evmVersion: 'cancun' is required for OpenZeppelin v5.4.0+ (mcopy opcode). (3) gasPrice: 5000000000000 (5000 gwei) prevents 'priority is too low' errors on TestNet. (4) requiredConfirmations: 1 prevents Ignition from misreading pending transactions as dropped.

Create 'contracts/MyNFT.sol' with the following OpenZeppelin ERC-721 contract.Use the inline content below:
```solidity
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.22;

import {ERC721} from '@openzeppelin/contracts/token/ERC721/ERC721.sol';
import {ERC721URIStorage} from '@openzeppelin/contracts/token/ERC721/extensions/ERC721URIStorage.sol';
import {Ownable} from '@openzeppelin/contracts/access/Ownable.sol';

contract MyNFT is ERC721, ERC721URIStorage, Ownable {
    uint256 private _nextTokenId;
    constructor(address initialOwner) ERC721('MyNFT', 'MNFT') Ownable(initialOwner) {}
    function safeMint(address to, string memory uri) public onlyOwner {
        uint256 tokenId = _nextTokenId++;
        _safeMint(to, tokenId);
        _setTokenURI(tokenId, uri);
    }
    function tokenURI(uint256 tokenId) public view override(ERC721, ERC721URIStorage) returns (string memory) { return super.tokenURI(tokenId); }
    function supportsInterface(bytes4 interfaceId) public view override(ERC721, ERC721URIStorage) returns (bool) { return super.supportsInterface(interfaceId); }
}
```

